var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이유리, 그쪽에도 없나?","JPN":"カスカベ、そこにもいないか？","ENG":"You don't see anything over there, Yuri?","TWN":"李悠麗，那裡也沒有嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"사람은커녕 시체도 안 보여.","JPN":"人どころか、死体すら無い。","ENG":"Nope. Not even a dead body.","TWN":"別說是活人，連個屍體都沒有。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"혹시 경찰이라도 다녀간 건 아닐까?","JPN":"もしかして警察が来てたとか？","ENG":"Maybe the cops have already been by?","TWN":"是不是員警來過了？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"경찰이 왔었으면 이 일대가 다 뒤집어졌을 거다.","JPN":"警察が来ていたなら、この一帯が大騒ぎになっているはずだ。","ENG":"The cops would have turned this entire neighborhood upside down.","TWN":"如果是員警，這一帶早就門庭若市了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"사방이 조용한 걸 보면 그건 아닐 것 같아.","JPN":"周りは静かだし、それはないだろう。","ENG":"It's too quiet for that.","TWN":"妳看周圍這麼安靜，員警應該沒來過。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그럼...... 지훈이랑 무기상 할아버지는?","JPN":"それじゃあ……ゴトウと武器屋のじいさんは？","ENG":"Then... what happened to Jihoon and the gunsmith?","TWN":"那麼……智勳和武器商爺爺呢？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"모르겠다. 살았는지, 죽었는지.","JPN":"知らない。生きているか、死んでいるかなんてな。","ENG":"I have no idea. Maybe they made it out. Maybe not.","TWN":"我也不知道是死是活。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그보다 우리에겐 시간이 없어. 도현이 놈 핸드폰은 찾았어?","JPN":"それより時間がない。リョウの携帯は見つけたか？","ENG":"But we don't have time to sit around and wonder about that. Have you found Dohyun's phone?","TWN":"我們沒時間管那麼多，找到道賢的手機了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"지금 지훈이보다 핸드폰이 더 중요해?","JPN":"ゴトウより携帯のほうが大事なの？","ENG":"Is that phone more important to you than Jihoon right now?","TWN":"手機比智勳的命更重要嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"내겐 중요해.","JPN":"俺にとっては大事だ。","ENG":"It is, to me.","TWN":"對我來說確實是。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"민병대에서 사람이 죽어나가는 건 흔한 일이지.","JPN":"民兵隊で人が死んでいくのはよくあることさ。","ENG":"People die all the time in the Militia.","TWN":"在民兵隊，隊員犧牲是常有的事。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 그 핸드폰 없이는 성냥팔이를 쫓을 수 없어.","JPN":"でも、あの携帯がないとマッチ売りを追跡できない。","ENG":"But we won't be able to track down the Matchmaker without the phone.","TWN":"但沒有那手機，我們就無法追蹤賣火柴組織。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"다들 왜 그렇게 매정한 거야?! 지훈이도 그렇고 대장까지!","JPN":"みんなどうしてそんなに薄情なんだ！？　ゴトウもそうだし、隊長まで！","ENG":"Why does everyone have to be so cold-hearted? First Jihoon, and now you...","TWN":"智勳也是，隊長也是！你們怎麼一個個都那麼無情！"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"지훈이에게 얼핏 들었어. 대장은 원래 경찰이었다면서?","JPN":"ゴトウから聞いたよ。隊長は元々警察官だったんだって？","ENG":"Jihoon sort of told me... that you used to be a cop.","TWN":"我聽智勳說過，隊長曾經當過員警是吧？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그리고 그 때의 부하들이 성냥팔이에게 당했다고, 그래서 복수하려는 거라고......","JPN":"昔の部下たちがマッチ売りにやられて、その復讐をするって……","ENG":"And you lost your men to the Matchmaker back then. That's why you want to take revenge...","TWN":"因為當時的部下被賣火柴組織殺害，所以才想要報仇……"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"젠장! 취급이 달라도 너무 다르잖아!","JPN":"ちくしょう！　扱いが全然違うじゃん！","ENG":"Drat it! Don't you think it's unfair?","TWN":"該死！這待遇差的也太大了吧？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"순직한 경찰들은 소중한 동료들이고, 우린 그저 대장의 총알받이야?!","JPN":"殉職した警察官たちは大切な仲間で、私たちはただの弾除けか？","ENG":"You care so much about those cops who died in the line of duty, but we're just meat shields to you?","TWN":"殉職的員警是他的同伴，而我們只配當炮灰？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......미, 미안해. 방금 말은 잊어 줘.","JPN":"……ご、ごめん。今の話は忘れて。","ENG":"S-sorry. Forget what I just said.","TWN":"……對、對不起。別在意。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"아니. 맞아. 총알받이다.","JPN":"いや、合っている。弾除けだ。","ENG":"No, you're right about the meat shield.","TWN":"不，妳說得對。是炮灰。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"너희들만 아니라, 나 역시도.","JPN":"お前たちだけじゃなく、俺もな。","ENG":"But not just you. Me, too.","TWN":"你們是，我也是。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이제 와서 이유가 뭐였는지는 중요하지 않아.","JPN":"今更理由が何かなんて重要じゃない。","ENG":"It doesn't matter why I'm after him anymore.","TWN":"事到如今，理由已經不重要了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"난 동료들의 복수를 하려는 것도, 정의를 집행하려는 것도 아니야.","JPN":"俺は同僚の復讐がしたいわけでも、正義を執行したいわけでもない。","ENG":"This isn't even about revenge or justice anymore.","TWN":"我不是想為同伴報仇，也不是想貫徹正義。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그저. 나 자신의 사적인 증오를 쏟아내고 싶을 뿐이다.","JPN":"ただ、自分の中の憎悪を吐き出したいだけだ。","ENG":"I just want to let out my personal anger against him.","TWN":"我只想，發洩我內心的憎惡。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"나는 그걸로 충분해.","JPN":"それで十分だ。","ENG":"That's enough for me.","TWN":"僅此而已。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"무슨 말이야 그게......?","JPN":"どういう意味だよ、それ……？","ENG":"What is that supposed to mean?","TWN":"什麼意思……？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"난 겨우 그따위 목적을 위해 민병대에 들어온 게 아니라고!","JPN":"私はそんな目的のために民兵隊に入ったんじゃない！","ENG":"I didn't join the Militia for some dumb reason like that!","TWN":"我才不是為了那種東西加入民兵隊的！"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장!","JPN":"隊長！","ENG":"Captain!","TWN":"隊長！"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......뭐야? 하다 하다 이젠 내분이라도 난 거야?","JPN":"……なんだ？　ついに仲間割れか？","ENG":"What's this? Have we resorted to infighting now?","TWN":"……什麼啊，你們起內訌了？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"최지훈?!","JPN":"ゴトウ！？","ENG":"Choi Jihoon?","TWN":"崔智勳？！"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"옷이 피투성이군. 네 피는 아닌 것 같은데.","JPN":"服が血まみれだな。お前の血ではなさそうだが。","ENG":"Your clothes are covered in blood. Doesn't seem like yours though.","TWN":"你身上全是血跡，但好像不是你自己的。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......무기상 영감 거야.","JPN":"……武器屋のジジイのだ。","ENG":"It's the gunsmith's.","TWN":"……是武器商老頭的。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"내 눈앞에서 총을 맞고 쓰러졌거든.","JPN":"俺の目の前で撃たれてやられた。","ENG":"He was shot down right in front of me.","TWN":"在我眼前被槍擊了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"꽤 강한 간부 놈이 나타나서 나 혼자만 겨우 빠져 나왔어.","JPN":"かなり強い幹部が出てきて、俺だけなんとか逃げられたんだ。","ENG":"Some strong capo appeared so I just barely managed to make it out by myself.","TWN":"遇到了一個實力強大的幹部，只有我一個人逃出來了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"둘이서 뭔가 이야기를 하길래 혹시 내 걱정이라도 하는 건가 싶어서 듣고 있었는데......","JPN":"二人とも真剣な顔でしゃべってっから、俺の心配でもしてるかと思ったら……","ENG":"Then I saw you two talking about something, so I was wondering if you were worried about me...","TWN":"我還以為你們在討論我的安危呢……"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"뭐 그럴 리가 없지. 평소의 민병대로구만.","JPN":"まあ、そんなはずがないか。いつもどおりの民兵隊だな。","ENG":"But of course you weren't. Just the same old heartless Militia.","TWN":"果然是我想多了，依舊是往常的民兵隊。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"야, 이 등신아! 살아 있었으면 바로 튀어 나왔어야지!","JPN":"おい、この野郎！　生きていたならすぐ出てこいよ！","ENG":"You moron! Why didn't you come sooner if you were alive?","TWN":"喂，你這笨蛋！我還以為你死掉了！"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장은 몰라도 난 정말 걱정했단 말야!","JPN":"隊長は知らないけど、私は本気で心配したんだ！","ENG":"I don't know about the Captain, but I was really worried about you!","TWN":"我和隊長可不一樣，我非常擔心你！"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"별 감흥이 없네. 넌 항상 세상 모든 걸 걱정하고 살잖아.","JPN":"そんなこと言われたってな。お前は常にこの世の全てを心配してんじゃないか。","ENG":"Meh, that doesn't sound like anything special. You're always worried about everything.","TWN":"我該感謝妳嗎，妳本來就喜歡杞人憂天。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그보다 이거나 받아.","JPN":"それより、ほら。","ENG":"Anyway, take this.","TWN":"拿著。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......핸드폰이로군. 데이터는 해독했나?","JPN":"……携帯か。データは解読できたか？","ENG":"It's the phone. Has the data been decrypted?","TWN":"……是手機啊。資料解密完成了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그래. 흥미로운 내용이 꽤 많더라고. 이것 봐.","JPN":"ああ。面白そうな内容が多かったぞ。ほら、見てみろ。","ENG":"Yup. And there was a lot of interesting stuff in there. Take a look at this.","TWN":"對，我發現了很多有趣的內容。看看這個。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이건...... 조직원들에게 보낸 전체 메시지군.","JPN":"これは……組織員全員に送ったメッセージだな。","ENG":"It's a message to everyone in the Matchmakers organization.","TWN":"這是……給組織成員發送的群發郵件。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"들개 사냥을 위해 보스가 임시 출소를 해서 별장에 대기하고 있다.","JPN":"野良犬狩りのためにボスが仮出所して別荘で待機している。","ENG":"The boss has temporarily left his cell and is standing by at the villa, ready to hunt down the wild dogs.","TWN":"老闆為了狩獵野狗臨時出獄，目前暫住在別墅。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"조직원들은 사냥 준비를 해서 집합할 것.","JPN":"組織員は狩りの準備をして集合するように。","ENG":"All members should prepare for the hunt and assemble.","TWN":"組織成員馬上集合準備狩獵。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"들개라니, 우리를 말하는 거야?","JPN":"野良犬って、私たちのこと？","ENG":"Wild dogs? Are they talking about us?","TWN":"野狗？是說我們嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그런 것 같군.","JPN":"そうみたいだな。","ENG":"So it seems.","TWN":"應該是。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"어쨌든 교도소에 쳐들어가는 것보다는 별장이 좀 더 낫겠지.","JPN":"刑務所に攻め込むよりは別荘のほうがマシだろう。","ENG":"In any case, storming the villa should be somewhat easier than breaking into prison.","TWN":"闖進別墅總比闖入牢獄裡好一些吧。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"우리에겐 다행이라고 할 수도 있어.","JPN":"俺たちにとっては朗報かもな。","ENG":"This could be good news for us.","TWN":"對我們來講也許是好事。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"트럭 챙겨서 먼저 출발해, 신입.","JPN":"トラックで先に出発しろ、新入り。","ENG":"Go ahead and take the truck, rookie.","TWN":"準備卡車，先出發吧，新人。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"난 지훈이와 무기를 마저 챙기고 따라갈 테니까.","JPN":"俺とゴトウは武器を全てまとめて持って行く。","ENG":"Jihoon and I will catch up with you once we've rounded up the rest of the weapons.","TWN":"我和智勳先準備武器後會馬上跟上。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그쪽에서 준비를 하고 있다면, 우리도 기대에 부응해 줘야겠지.","JPN":"向こうが準備をしているなら、俺らも期待に応えてやらないとな。","ENG":"If they're getting ready for us, we shouldn't let them down.","TWN":"既然對方做了那麼多準備，那我們也不能讓他們失望。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};